                className="mt-4 flex items-center gap-2 px-4 py-3 rounded-xl text-xs font-bold"
                style={{ background: `${theme.danger}15`, border: `1px solid ${theme.danger}30`, color: theme.danger }}>
                <AlertCircle size={14} />{aiError}
              </motion.div>
            )}
          </AnimatePresence>
