const regexFallback = (buffer) => {
  const raw = buffer.toString('latin1');
  const textChunks = [];

  // 1. Match standard (Text) strings
  const parenRe = /\(([^)\\]*(?:\\.[^)\\]*)*)\)\s*(?:Tj|TJ|'|")/g;
  let m;
  while ((m = parenRe.exec(raw)) !== null) {
    let t = m[1]
      .replace(/\\n/g, '\n')
      .replace(/\\r/g, '')
      .replace(/\\\\/g, '\\')
      .replace(/\\([0-7]{3})/g, (_, o) => String.fromCharCode(parseInt(o, 8)))
      .replace(/\\(.)/g, '$1');
    if (t.trim().length > 1) textChunks.push(t);
  }

  // 2. Match <HEX> strings
  const hexRe = /<([0-9A-Fa-f]{2,})>\s*(?:Tj|TJ|'|")/g;
  while ((m = hexRe.exec(raw)) !== null) {
    try {
      const hex = m[1];
      let decoded = '';
      for (let i = 0; i < hex.length; i += 2) {
        decoded += String.fromCharCode(parseInt(hex.substr(i, 2), 16));
      }
      if (decoded.trim().length > 1) textChunks.push(decoded);
    } catch (e) {}
  }

  return textChunks.join(' ').replace(/\s+/g, ' ').trim();
};

