import type { ChunkRecord } from './types';

const STORE_KEY = 'studyx-ai-vectors';

function loadStore(): ChunkRecord[] {
  try {
    const raw = localStorage.getItem(STORE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

