import type { ChunkRecord } from './types';
import { idbGet, idbSet, idbRemove } from '../lib/idb';

const STORE_KEY = 'studyx-ai-vectors';

// Memory cache for synchronous similarity search
let memoryCache: ChunkRecord[] | null = null;

export async function loadStore(): Promise<ChunkRecord[]> {
  if (memoryCache) return memoryCache;
  try {
    const raw = await idbGet<ChunkRecord[]>(STORE_KEY);
    memoryCache = Array.isArray(raw) ? raw : [];
    return memoryCache;
  } catch {
    memoryCache = [];
    return [];
  }
}

export async function saveStore(chunks: ChunkRecord[]) {
  try {
    memoryCache = chunks;
    await idbSet(STORE_KEY, chunks);
  } catch {}
}

export async function addChunks(chunks: ChunkRecord[]) {
  const current = await loadStore();
  const merged = [...current.filter((item) => !chunks.some((chunk) => chunk.id === item.id)), ...chunks];
  await saveStore(merged);
}

export async function clearChunks() {
  memoryCache = [];
  await idbRemove(STORE_KEY);
}

export async function getAllChunks() {
  return await loadStore();
}

export async function similaritySearch(query: string, k: number, scoreFn: (chunk: ChunkRecord, query: string) => number) {
  const chunks = await loadStore();
  return chunks
    .map((chunk) => ({ chunk, score: scoreFn(chunk, query) }))
    .sort((a, b) => b.score - a.score)
    .slice(0, k);
}

