      return {
        id: chunk.id,
        text: chunk.text,
        topic: chunk.topic,
        source: chunk.source,
        difficulty: chunk.difficulty,
        score,
        keywordScore: keyword,
        semanticScore,
        recencyBoost,
        weaknessBoost,
      };
    })
    .sort((a, b) => b.score - a.score)
    .slice(0, k);
}

