export async function parseImageOCR(file: File | string): Promise<string> {
  // If it's a string (base64 or URL), we handle it accordingly
  // For simplicity, we mostly expect File objects here from the input

  try {
    const { createWorker } = await import('tesseract.js');
    const worker = await createWorker('ron'); // Start with Romanian

    let source: any = file;
    if (typeof file === 'string' && file.startsWith('data:')) {
      source = file;
    }

    const ret = await worker.recognize(source);
    await worker.terminate();

    return cleanText(ret.data.text);
  } catch (e) {
    console.error('OCR Error:', e);
    return '';
  }
}

