import { motion, AnimatePresence } from 'framer-motion';
import { useState, useRef, useEffect } from 'react';
import { 
  Library, Upload, FileText, Trash2, Search, 
  Sparkles, Bot, Brain, Database, Plus, ChevronRight,
  BookOpen, Clock, FileType, CheckCircle2, AlertCircle, Loader2
} from 'lucide-react';
import { useTheme } from '../theme/ThemeContext';
import { useAIStore, type AIKnowledgeSource } from '../store/aiStore';
import { parsePDF } from '../ai/pdfParser';
import { parseDocx } from '../ai/docxParser';
import { parseImageOCR } from '../ai/ocrParser';

export default function KnowledgeVault() {
  const theme = useTheme();
  const { knowledgeSources, addKnowledgeSource, removeKnowledgeSource, clearKnowledgeSources, isHydrated } = useAIStore();
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const filtered = knowledgeSources.filter(s => 
    s.name.toLowerCase().includes(search.toLowerCase()) || 
    s.content.toLowerCase().includes(search.toLowerCase())
  ).sort((a, b) => b.addedAt - a.addedAt);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    setLoading(true);
    setError(null);

    try {
      for (const file of files) {
        const isPdf = file.name.toLowerCase().endsWith('.pdf');
        const isDocx = file.name.toLowerCase().endsWith('.docx');
        const isImage = /\.(jpe?g|png|webp|bmp)$/i.test(file.name);

        let text = '';
        let type: any = 'txt';

        if (isPdf) {
          text = await parsePDF(file);
          type = 'pdf';
        } else if (isDocx) {
          text = await parseDocx(file);
          type = 'docx';
        } else if (isImage) {
          text = await parseImageOCR(file);
          type = 'image';
        } else {
          text = await file.text();
        }

        if (text.trim().length < 20) {
          throw new Error(`Conținut insuficient în ${file.name}`);
        }

        await addKnowledgeSource(file.name, text, type);
      }
    } catch (err: any) {
      setError(err.message || 'Eroare la procesarea fișierelor.');
    } finally {
      setLoading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const totalWords = knowledgeSources.reduce((acc, s) => acc + s.content.split(/\s+/).length, 0);
  const totalChars = knowledgeSources.reduce((acc, s) => acc + s.content.length, 0);

  return (
    <div className="h-full overflow-y-auto px-4 sm:px-8 py-6 sm:py-10">
      <div className="max-w-5xl mx-auto">

        {/* Header */}
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="mb-10">
          <div className="flex items-end justify-between gap-6 flex-wrap">
            <div>
              <div className="flex items-center gap-3 mb-2">
                <div className="w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg"
                  style={{ background: `linear-gradient(135deg, ${theme.accent}, ${theme.accent2})`, color: '#fff' }}>
                  <Database size={20} />
                </div>
                <h1 className="text-3xl font-black tracking-tight" style={{ color: theme.text }}>
                  Knowledge <span style={{ color: theme.accent }}>Vault</span>
                </h1>
              </div>
              <p className="text-sm font-medium opacity-60 max-w-md" style={{ color: theme.text }}>
                Centrul tău local de date. AI-ul StudyX folosește aceste documente pentru a-ți oferi răspunsuri bazate strict pe cursurile tale.
              </p>
            </div>
            <div className="flex items-center gap-3">
              <input 
                type="file" 
                ref={fileInputRef} 
                multiple 
                accept=".pdf,.docx,.txt,.md,image/*" 
                className="hidden" 
                onChange={handleFileUpload} 
              />
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                onClick={() => fileInputRef.current?.click()}
                disabled={loading}
                className="flex items-center gap-2 px-6 py-3 rounded-2xl font-black text-white shadow-xl transition-all"
                style={{ background: theme.accent, boxShadow: `0 8px 24px ${theme.accent}40` }}>
                {loading ? <Loader2 size={18} className="animate-spin" /> : <Plus size={18} />}
                Adaugă Documente
              </motion.button>
            </div>
          </div>
        </motion.div>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-10">
          {[
            { label: 'Documente', value: knowledgeSources.length, icon: <Library size={18} />, color: theme.accent },
            { label: 'Total Cuvinte', value: totalWords.toLocaleString(), icon: <FileType size={18} />, color: theme.accent2 },
            { label: 'Capacitate AI', value: `${((totalChars / 1000000) * 100).toFixed(1)}%`, icon: <Brain size={18} />, color: theme.success },
          ].map((s, i) => (
            <motion.div key={s.label}
              initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.1 + i * 0.05 }}
              className="rounded-[24px] p-5 relative overflow-hidden"
              style={{ background: theme.surface, border: `1px solid ${theme.border}` }}>
              <div className="flex items-center gap-3 mb-3">
                <div className="w-8 h-8 rounded-xl flex items-center justify-center"
                  style={{ background: `${s.color}15`, color: s.color }}>
                  {s.icon}
                </div>
                <span className="text-[10px] font-black uppercase tracking-widest opacity-50" style={{ color: theme.text }}>{s.label}</span>
              </div>
              <div className="text-2xl font-black tracking-tight" style={{ color: theme.text }}>{s.value}</div>
            </motion.div>
          ))}
        </div>

        {/* Search & List */}
        <div className="space-y-6">
          <div className="relative">
            <div className="absolute left-4 top-1/2 -translate-y-1/2 opacity-40">
              <Search size={18} style={{ color: theme.text }} />
            </div>
            <input 
              type="text"
              placeholder="Caută în bibliotecă..."
