const { app, BrowserWindow, ipcMain, shell, dialog, Notification, Tray, nativeImage, Menu, session } = require('electron');
const path = require('path');
const fs = require('fs');
const { registerUpdaterIPC } = require('./updater.cjs');

const isDev = !app.isPackaged;

// ── GPU disk-cache suppression ───────────────────────────────────────────────
// Prevents "Unable to move the cache: Access is denied" (0x5) errors that
// appear when the OS or another process temporarily holds the GPU shader-cache
// directory lock.  These are harmless but pollute the console.
// Must be called before app.whenReady().
app.commandLine.appendSwitch('disable-gpu-shader-disk-cache');

// ── 1. Dev vs Prod userData isolation ───────────────────────────────────────
// Must be called before app.whenReady() and before any app.getPath('userData') call
if (!app.isPackaged) {
  const devData = path.join(app.getPath('appData'), 'StudyX-Dev');
  app.setPath('userData', devData);
}

let mainWindow = null;
let tray = null;

function createWindow() {
  // Resolve icon path — works both in dev and in packaged builds
  const iconPath = path.join(__dirname, '../public/icon.png');

  mainWindow = new BrowserWindow({
    width: 1400,
    height: 880,
    minWidth: 1000,
    minHeight: 660,
    frame: false,
    backgroundColor: '#1a1a2e', // near-black purple — matches Obsidian theme bg, hides flash
    titleBarStyle: 'hidden',
    webPreferences: {
      nodeIntegration: false,
      contextIsolation: true,
      preload: path.join(__dirname, 'preload.cjs'),
      defaultEncoding: 'UTF-8',
    },
    icon: fs.existsSync(iconPath) ? iconPath : undefined,
    show: false,
  });

  // Show window only after React signals readiness (eliminates white flash)
  ipcMain.once('app:ready', () => mainWindow?.show());
  // Fallback: show after 4s if app:ready never fires (e.g. blank-page crash)
  setTimeout(() => { if (mainWindow && !mainWindow.isVisible()) mainWindow.show(); }, 4000);

  if (isDev) {
    mainWindow.loadURL('http://localhost:5173');
  } else {
    // Prefer overlay in userData (written by in-app updater, always writable even in Program Files).
    // Falls back to the installed dist/ if no overlay exists yet.
    const overlayHtml = path.join(app.getPath('userData'), 'app-overlay', 'files', 'dist', 'index.html');
    const loadPath = fs.existsSync(overlayHtml)
      ? overlayHtml
      : path.join(__dirname, '../dist/index.html');
    mainWindow.loadFile(loadPath);
  }

  // Window state IPC
  ipcMain.on('win:minimize', () => mainWindow?.minimize());
  ipcMain.on('win:maximize', () => {
    if (mainWindow?.isMaximized()) mainWindow.unmaximize();
    else mainWindow?.maximize();
  });
  ipcMain.on('win:close', () => mainWindow?.close());
  ipcMain.handle('win:isMaximized', () => mainWindow?.isMaximized() ?? false);

  mainWindow.on('maximize', () => mainWindow?.webContents.send('win:maximized', true));
  mainWindow.on('unmaximize', () => mainWindow?.webContents.send('win:maximized', false));

  // Close button quits the app completely (no background running)
  mainWindow.on('close', () => {
    app.quit();
  });

  // File import IPC
  ipcMain.handle('dialog:openJson', async () => {
    const result = await dialog.showOpenDialog(mainWindow, {
      properties: ['openFile', 'multiSelections'],
      filters: [{ name: 'JSON Files', extensions: ['json'] }],
    });
    if (result.canceled) return null;
    const files = result.filePaths.map((p) => ({
      name: path.basename(p),
      content: fs.readFileSync(p, 'utf-8'),
    }));
    return files;
  });

  // Save file dialog — for backup export
  ipcMain.handle('dialog:saveFile', async (_, { defaultPath, content }) => {
    const result = await dialog.showSaveDialog(mainWindow, {
      defaultPath,
      filters: [{ name: 'JSON', extensions: ['json'] }],
    });
    if (result.canceled || !result.filePath) return false;
    fs.writeFileSync(result.filePath, content, 'utf-8');
    return true;
  });

  // Helper for PDF extraction
  const extractPdfText = async (filePath) => {
    const regexFallback = (buffer) => {
      const raw = buffer.toString('latin1');
      const textChunks = [];
      const arrayRe = /\[((?:\([^)]*\)|-?\d+(?:\.\d+)?|\s+)+)\]\s*TJ/g;
      let m;
      while ((m = arrayRe.exec(raw)) !== null) {
        const content = m[1];
        const innerParenRe = /\(([^)]*)\)/g;
        while ((innerParenRe.exec(content)) !== null) {
          let t = RegExp.$1.replace(/\\([0-7]{3})/g, (_, o) => String.fromCharCode(parseInt(o, 8)))
                           .replace(/\\n/g, '\n').replace(/\\r/g, '').replace(/\\\\/g, '\\');
          if (t.trim().length > 0) textChunks.push(t);
        }
      }
      const parenRe = /\(([^)\\]*(?:\\.[^)\\]*)*)\)\s*(?:Tj|'|")/g;
      while ((m = parenRe.exec(raw)) !== null) {
        let t = m[1]
          .replace(/\\([0-7]{3})/g, (_, o) => String.fromCharCode(parseInt(o, 8)))
          .replace(/\\n/g, '\n').replace(/\\r/g, '').replace(/\\\\/g, '\\')
          .replace(/\\(.)/g, '$1');
        if (t.trim().length > 0) textChunks.push(t);
      }
      const hexRe = /<([0-9A-Fa-f]{2,})>/g;
      while ((m = hexRe.exec(raw)) !== null) {
        try {
          const hex = m[1];
          let decoded = '';
          for (let i = 0; i < hex.length; i += 2) {
            const charCode = parseInt(hex.substr(i, 2), 16);
            if (charCode >= 32) decoded += String.fromCharCode(charCode);
          }
          if (decoded.trim().length > 1) textChunks.push(decoded);
        } catch (e) {}
      }
      return textChunks.join(' ').replace(/\s+/g, ' ').trim();
    };

    try {
      const pdfParse = require('pdf-parse');
      const buffer = fs.readFileSync(filePath);
      const options = {
        pagerender: (pageData) => {
          return pageData.getTextContent().then(textContent => {
            let lastY, text = '';
            for (let item of textContent.items) {
              if (lastY === item.transform[5] || !lastY) text += item.str;
              else text += '\n' + item.str;
              lastY = item.transform[5];
            }
            return text;
          });
        }
      };
      const data = await pdfParse(buffer, options);
      const pdfText = data.text.replace(/\s+/g, ' ').trim();
      const fallbackText = regexFallback(buffer);
      const result = pdfText.length > fallbackText.length ? pdfText : fallbackText;
      return result.length > 50 ? result : null;
    } catch (err) {
      try {
        const buffer = fs.readFileSync(filePath);
        const fallback = regexFallback(buffer);
        return fallback.length > 50 ? fallback : null;
      } catch { return null; }
    }
  };

  // PDF import IPC — returns extracted text content
  ipcMain.handle('dialog:openPdf', async () => {
    const result = await dialog.showOpenDialog(mainWindow, {
      properties: ['openFile'],
      filters: [{ name: 'PDF Files', extensions: ['pdf'] }],
    });
    if (result.canceled || result.filePaths.length === 0) return null;
    return extractPdfText(result.filePaths[0]);
  });

  // Direct PDF path reading (e.g. for drag and drop)
  ipcMain.handle('pdf:readPath', async (_, filePath) => {
    return extractPdfText(filePath);
  });

  // DOCX extraction helper
  const extractDocxText = async (filePath) => {
    try {
      const mammoth = require('mammoth');
      const result = await mammoth.extractRawText({ path: filePath });
      return result.value.trim();
    } catch (e) {
      console.error('Error extracting docx:', e);
      return null;
    }
  };

  // DOCX import IPC
  ipcMain.handle('dialog:openDocx', async () => {
    const result = await dialog.showOpenDialog(mainWindow, {
      properties: ['openFile'],
      filters: [{ name: 'Word Documents', extensions: ['docx'] }],
    });
    if (result.canceled || result.filePaths.length === 0) return null;
    return extractDocxText(result.filePaths[0]);
  });

  // Direct DOCX path reading
  ipcMain.handle('docx:readPath', async (_, filePath) => {
    if (!filePath) return null;
    return extractDocxText(filePath);
  });

  // OCR extraction helper
  const extractOCRText = async (filePath) => {
    try {
      const { createWorker } = require('tesseract.js');
      const worker = await createWorker('ron'); // Start with Romanian
      const ret = await worker.recognize(filePath);
      await worker.terminate();
      return ret.data.text.trim();
    } catch (e) {
      console.error('OCR Error:', e);
      return null;
    }
  };

  // Image OCR import IPC
  ipcMain.handle('dialog:openImage', async () => {
    const result = await dialog.showOpenDialog(mainWindow, {
      properties: ['openFile'],
      filters: [{ name: 'Images', extensions: ['jpg', 'jpeg', 'png', 'webp', 'bmp'] }],
    });
    if (result.canceled || result.filePaths.length === 0) return null;
    return extractOCRText(result.filePaths[0]);
  });

  // Direct image path reading for OCR
  ipcMain.handle('image:readOCR', async (_, filePath) => {
    if (!filePath) return null;
    return extractOCRText(filePath);
  });

  // Text import IPC — plain text/markdown files for AI knowledge library
  ipcMain.handle('dialog:openText', async () => {
    const result = await dialog.showOpenDialog(mainWindow, {
      properties: ['openFile'],
      filters: [
        { name: 'Text Files', extensions: ['txt', 'md', 'markdown'] },
        { name: 'All Files', extensions: ['*'] },
      ],
    });
    if (result.canceled || result.filePaths.length === 0) return null;
    const filePath = result.filePaths[0];
    try {
      return fs.readFileSync(filePath, 'utf-8');
    } catch {
      return null;
    }
  });

  // Image import IPC — returns base64 data URL
  ipcMain.handle('dialog:openImage', async () => {
    const result = await dialog.showOpenDialog(mainWindow, {
      properties: ['openFile'],
      filters: [{ name: 'Images', extensions: ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp'] }],
    });
    if (result.canceled || result.filePaths.length === 0) return null;
    const filePath = result.filePaths[0];
    const ext = path.extname(filePath).toLowerCase().slice(1);
    const mimeMap = { jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png', gif: 'image/gif', webp: 'image/webp', bmp: 'image/bmp' };
    const mime = mimeMap[ext] || 'image/jpeg';
    const data = fs.readFileSync(filePath);
    return `data:${mime};base64,${data.toString('base64')}`;
  });

  // Screenshot protection toggle
  ipcMain.handle('win:setContentProtection', (_, enabled) => {
    mainWindow?.setContentProtection(enabled);
    return true;
  });

  // Hardware acceleration setting (stored in userData, applied on next launch)
  ipcMain.handle('app:setHardwareAccel', (_, enabled) => {
    const settingsPath = path.join(app.getPath('userData'), 'settings.json');
    let settings = {};
    try { settings = JSON.parse(fs.readFileSync(settingsPath, 'utf-8')); } catch {}
    settings.hardwareAccel = enabled;
    fs.writeFileSync(settingsPath, JSON.stringify(settings), 'utf-8');
    return true;
  });

  // Get current settings
  ipcMain.handle('app:getSettings', () => {
    const settingsPath = path.join(app.getPath('userData'), 'settings.json');
    try { return JSON.parse(fs.readFileSync(settingsPath, 'utf-8')); } catch { return {}; }
  });

  // ── 4. Hard Reset — wipe all app data and relaunch ───────────────────────
  ipcMain.handle('app:hardReset', async () => {
    try {
      // Clear renderer localStorage / IndexedDB / cache
      await mainWindow?.webContents.session.clearStorageData({
        storages: ['localstorage', 'indexdb', 'cookies', 'cachestorage', 'shadercache'],
      });
      // Remove userData directory contents (settings, sentinel, etc.)
      const ud = app.getPath('userData');
      for (const entry of fs.readdirSync(ud)) {
        const full = path.join(ud, entry);
        try {
          const stat = fs.statSync(full);
          if (stat.isDirectory()) fs.rmSync(full, { recursive: true, force: true });
          else fs.unlinkSync(full);
        } catch {}
      }
    } catch (e) {
      console.warn('[StudyX] Hard reset cleanup error:', e);
    }
    app.relaunch();
    app.quit();
    return true;
  });

  // Save file as CSV (for Anki export)
  ipcMain.handle('dialog:saveCsv', async (_, { defaultPath, content }) => {
    const result = await dialog.showSaveDialog(mainWindow, {
      defaultPath,
      filters: [{ name: 'CSV', extensions: ['csv'] }],
    });
    if (result.canceled || !result.filePath) return false;
    fs.writeFileSync(result.filePath, content, 'utf-8');
    return true;
  });

  // ── Auto-Backup: write a dated JSON snapshot to Documents/StudyX-Backups ──
  ipcMain.handle('app:autoBackup', async (_, { data }) => {
    try {
      const docsPath = app.getPath('documents');
      const backupDir = path.join(docsPath, 'StudyX-Backups');
      fs.mkdirSync(backupDir, { recursive: true });

      // Keep only the latest 10 backups (rotating)
      const existing = fs.readdirSync(backupDir)
        .filter(f => f.startsWith('studyx-backup-') && f.endsWith('.json'))
        .sort();
      while (existing.length >= 10) {
        try { fs.unlinkSync(path.join(backupDir, existing.shift())); } catch {}
      }

      const dateStr = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
      const filePath = path.join(backupDir, `studyx-backup-${dateStr}.json`);
      fs.writeFileSync(filePath, data, 'utf-8');

      return { success: true, path: filePath };
    } catch (e) {
      return { success: false, error: e.message };
    }
  });
}

// Daily study reminder — fires once per day if user hasn't studied
function scheduleDailyReminder() {
  if (!Notification.isSupported()) return;

  const checkAndNotify = () => {
    const today = new Date().toISOString().split('T')[0];
    const stored = app.getPath('userData') + '/last-notified.txt';
    let lastNotified = '';
    try { lastNotified = fs.readFileSync(stored, 'utf-8').trim(); } catch {}
    if (lastNotified === today) return;

    // Read localStorage from renderer to check last study date
    if (mainWindow) {
      mainWindow.webContents.executeJavaScript(`
        (() => {
          try {
            // Newer app versions store stats per-profile under studyx-p-<id>-stats.
            // Fallback to legacy global key for backward compatibility.
            const activeRaw = localStorage.getItem('studyx-user');
            const activeState = activeRaw ? JSON.parse(activeRaw)?.state ?? JSON.parse(activeRaw) : null;
            const profileId = activeState?.activeProfileId;
            if (profileId) {
              const perProfileRaw = localStorage.getItem(\`studyx-p-\${profileId}-stats\`);
              if (perProfileRaw) {
                const perProfile = JSON.parse(perProfileRaw);
